const input = $json;
const message = input.message || {};
const rawText = String(message.text || message.caption || '');
const normalizedText = rawText.trim().replace(/\s+/g, ' ');
const lower = normalizedText.toLocaleLowerCase('uk-UA');
const urls = normalizedText.match(/https?:\/\/[^\s]+/gi) || [];
const photo = Array.isArray(message.photo) ? message.photo.at(-1) : null;
const voice = message.voice || null;
const document = message.document || null;
const mediaKind = voice ? 'voice' : photo ? 'photo' : document ? 'document' : null;
const file = voice || photo || document || {};
const mimeType = String(file.mime_type || (photo ? 'image/jpeg' : '')).toLowerCase();
const fileName = String(document?.file_name || (voice ? `voice-${message.message_id}.ogg` : photo ? `photo-${message.message_id}.jpg` : ''));
const fileSize = Number(file.file_size || 0);
const knownDocument = /\.(pdf|docx|xlsx|pptx|txt|md|csv|json|xml)$/i.test(fileName);
const blockedDocument = Boolean(document) && (/\.(zip|rar|7z|tar|gz)$/i.test(fileName) || /(?:zip|x-rar|x-7z|x-tar|gzip)/i.test(mimeType) || (!knownDocument && /octet-stream/i.test(mimeType)));
const oversizedDocument = Boolean(document) && fileSize > 20 * 1024 * 1024;
const forceCapture = /^\/(save|inbox)(?:@\w+)?(?:\s|$)/i.test(normalizedText);
const documentSearchCommand = /^\/(docsearch|docs|doc)(?:@\w+)?(?:\s|$)/i.test(normalizedText);
const documentSearchPhrase = /^(знайди|знайдіть|покажи|покажіть|пошукай|пошукайте)\s+(?:в|у)\s+(?:документах?|файлах?)(?=\s|$)/i.test(lower);
const searchScope = documentSearchCommand || documentSearchPhrase ? 'documents' : 'all';
const searchIntent = !mediaKind && !forceCapture && (
  documentSearchCommand || documentSearchPhrase ||
  /^\/(search|find)(?:@\w+)?(?:\s|$)/i.test(normalizedText) ||
  /^(знайди|знайдіть|покажи|покажіть|що я знаю|що в мене є|які (?:в мене|у мене)|пошукай|де (?:в мене|у мене))(?=\s|$)/i.test(lower)
);
let query = normalizedText.replace(/^\/(search|find|docsearch|docs|doc)(?:@\w+)?(?:\s+|$)/i, '').trim();
if (searchScope === 'documents') query = query.replace(/^(знайди|знайдіть|покажи|покажіть|пошукай|пошукайте)\s+(?:в|у)\s+(?:документах?|файлах?)\s*/i, '').trim();
const captureText = normalizedText.replace(/^\/(save|inbox)(?:@\w+)?\s*/i, '').trim();
const supported = mediaKind ? !blockedDocument && !oversizedDocument : normalizedText.length > 0;
const unsupportedReason = blockedDocument ? 'archive_or_opaque_binary' : oversizedDocument ? 'file_over_20mb' : null;

return [{ json: {
  telegram_user_id: String(message.from?.id || ''),
  source_message_id: String(message.message_id || ''),
  source_chat_id: String(message.chat?.id || ''),
  content_type: voice ? 'voice' : photo ? 'photo' : document ? 'file' : urls.length > 0 ? 'link' : 'text',
  raw_text: rawText,
  normalized_text: forceCapture ? captureText : normalizedText,
  source_url: urls[0] || null,
  supported,
  unsupported_reason: unsupportedReason,
  intent: searchIntent ? 'search' : 'capture',
  search_scope: searchScope,
  query,
  media_kind: mediaKind,
  file_id: String(file.file_id || ''),
  file_unique_id: String(file.file_unique_id || ''),
  file_name: fileName,
  mime_type: mimeType,
  file_size: fileSize,
  raw_payload: input
} }];

const row = $json;
const source = String(row.source_url || '').trim();
const match = source.match(/^(https?):\/\/([^\/?#]+)([^\s]*)$/i);
if (!match) return [];
const protocol = match[1].toLowerCase();
const authority = match[2];
if (authority.includes('@')) return [];
let host = authority.toLowerCase();
if (host.startsWith('[')) {
  const end = host.indexOf(']');
  if (end < 0) return [];
  host = host.slice(1, end);
} else {
  host = host.split(':')[0];
}
const blockedName = host === 'localhost' || host.endsWith('.localhost') || host.endsWith('.local') || host.endsWith('.internal') || host === 'metadata.google.internal';
const blockedIpv4 = /^(?:0\.|10\.|127\.|169\.254\.|192\.168\.|100\.(?:6[4-9]|[7-9]\d|1[01]\d|12[0-7])\.)/.test(host)
  || /^172\.(?:1[6-9]|2\d|3[01])\./.test(host);
const blockedIpv6 = host === '::1' || host.startsWith('fc') || host.startsWith('fd') || host.startsWith('fe80:');
if (blockedName || blockedIpv4 || blockedIpv6) return [];
const normalizedUrl = `${protocol}://${authority}${match[3] || ''}`.replace(/#.*$/, '');
return [{ json: { ...row, source_url: normalizedUrl, web_host: host } }];

const original = $('Validate Web URL').first().json;
const result = $json || {};
const duration = Number(result.duration || 0);
const transcriptCharacters = Number(result.transcript_characters || 0);
const transcriptReady = transcriptCharacters > 0;
const extractionStatus = transcriptReady ? 'transcript_ready' : (result.ok ? (result.transcript_error ? 'caption_error' : 'metadata_only') : 'failed');
const limitation = transcriptReady ? '' : 'УВАГА: транскрипт відео недоступний. Аналізуй лише назву, опис, метадані та розділи; не стверджуй, що це аналіз повного змісту відео.';
const durationText = duration ? `${Math.floor(duration / 3600)}:${String(Math.floor((duration % 3600) / 60)).padStart(2, '0')}:${String(duration % 60).padStart(2, '0')}` : '';
const chapters = Array.isArray(result.chapters) ? result.chapters.map((chapter) => {
  const seconds = Number(chapter.start_time || 0);
  const stamp = `${Math.floor(seconds / 60)}:${String(Math.floor(seconds % 60)).padStart(2, '0')}`;
  return `${stamp} ${chapter.title || ''}`.trim();
}).filter(Boolean).join('\n') : '';
const parts = [
  result.title ? `Назва: ${result.title}` : '',
  limitation,
  result.channel ? `Канал: ${result.channel}` : '',
  result.upload_date ? `Дата публікації: ${String(result.upload_date).replace(/^(\d{4})(\d{2})(\d{2})$/, '$1-$2-$3')}` : '',
  durationText ? `Тривалість: ${durationText}` : '',
  result.description ? `Опис:\n${result.description}` : '',
  chapters ? `Розділи:\n${chapters}` : '',
  result.transcript ? `Транскрипт (${result.language || 'unknown'}, ${result.subtitle_type || 'captions'}):\n${result.transcript}` : ''
].filter(Boolean);
const extracted = parts.join('\n\n').slice(0, 120000).trim();
const fallback = String(original.normalized_text || original.source_url || '').trim();
const normalized = extracted || fallback;
return [{ json: {
  ...original,
  raw_text: fallback,
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: {
    ...original.raw_payload,
    extraction: {
      provider: 'yt-dlp',
      status: extractionStatus,
      complete: transcriptReady,
      metadata_complete: Boolean(result.ok),
      video_id: result.id || null,
      title: result.title || '',
      channel: result.channel || '',
      duration: duration || null,
      language: result.language || null,
      subtitle_type: result.subtitle_type || null,
      transcript_characters: transcriptCharacters,
      error: result.error || result.transcript_error || null
    }
  }
} }];

const original = $('Validate Web URL').first().json;
const response = $json || {};
const statusCode = Number(response.statusCode || 0);
const headers = response.headers || {};
const contentType = String(headers['content-type'] || headers['Content-Type'] || '').toLowerCase();
let body = typeof response.body === 'string' ? response.body : typeof response.data === 'string' ? response.data : typeof response === 'string' ? response : '';
body = body.slice(0, 1500000);

const decode = (value) => String(value || '')
  .replace(/&#(\d+);/g, (_, n) => String.fromCodePoint(Number(n)))
  .replace(/&#x([0-9a-f]+);/gi, (_, n) => String.fromCodePoint(parseInt(n, 16)))
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&quot;/gi, '"')
  .replace(/&#39;|&apos;/gi, "'")
  .replace(/&lt;/gi, '<')
  .replace(/&gt;/gi, '>');

let title = '';
let description = '';
let text = '';
if (/html|xhtml/.test(contentType) || /<html|<body|<article/i.test(body)) {
  title = decode((body.match(/<title[^>]*>([\s\S]*?)<\/title>/i) || [])[1]).replace(/\s+/g, ' ').trim();
  description = decode((body.match(/<meta[^>]+(?:name|property)=["'](?:description|og:description)["'][^>]+content=["']([\s\S]*?)["'][^>]*>/i) || body.match(/<meta[^>]+content=["']([\s\S]*?)["'][^>]+(?:name|property)=["'](?:description|og:description)["'][^>]*>/i) || [])[1]).replace(/\s+/g, ' ').trim();
  text = body
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<(script|style|svg|canvas|noscript|template|form|nav|footer|header|aside)[^>]*>[\s\S]*?<\/\1>/gi, ' ')
    .replace(/<(br|p|div|section|article|main|h[1-6]|li|tr|blockquote)[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, ' ');
  text = decode(text);
} else if (contentType.startsWith('text/') || body) {
  text = body;
}
text = text.replace(/\r/g, '').replace(/[ \t]+/g, ' ').replace(/ *\n */g, '\n').replace(/\n{3,}/g, '\n\n').trim();
const useful = [title, description, text].filter(Boolean).join('\n\n').slice(0, 120000).trim();
const fallback = String(original.normalized_text || original.source_url || '').trim();
const normalized = useful.length >= 200 ? useful : fallback;
return [{ json: {
  ...original,
  raw_text: fallback,
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: {
    ...original.raw_payload,
    extraction: {
      provider: 'direct-html',
      status_code: statusCode,
      content_type: contentType,
      title,
      extracted_characters: useful.length,
      complete: useful.length >= 200
    }
  }
} }];

if ($json.intent !== 'search' || !$json.query) return [];
return [{ json: {
  telegram_user_id: $json.telegram_user_id,
  source_chat_id: $json.source_chat_id,
  search_scope: $json.search_scope || 'all',
  query: $json.query
} }];

const original = $('Normalize Telegram Input').first().json;
const mime = String(original.mime_type || '').toLowerCase();
const name = String(original.file_name || '').toLowerCase();
const local = mime.startsWith('text/')
  || /application\/(json|xml|csv)/i.test(mime)
  || /\.(txt|md|csv|json|xml)$/.test(name);
return local ? [{ json: $json, binary: $binary }] : [];

const original = $('Normalize Telegram Input').first().json;
const mime = String(original.mime_type || '').toLowerCase();
const name = String(original.file_name || '').toLowerCase();
const local = mime.startsWith('text/')
  || /application\/(json|xml|csv)/i.test(mime)
  || /\.(txt|md|csv|json|xml)$/.test(name);
const pdf = mime === 'application/pdf' || name.endsWith('.pdf');
const office = /\.(docx|xlsx|pptx)$/.test(name) || /officedocument/i.test(mime);
return local || pdf || office ? [] : [{ json: $json, binary: $binary }];

const original = $('Normalize Telegram Input').first().json;
const mime = String(original.mime_type || '').toLowerCase();
const name = String(original.file_name || '').toLowerCase();
const pdf = mime === 'application/pdf' || name.endsWith('.pdf');
return pdf ? [{ json: $json, binary: $binary }] : [];

const original = $('Normalize Telegram Input').first().json;
const mime = String(original.mime_type || '').toLowerCase();
const name = String(original.file_name || '').toLowerCase();
const office = /\.(docx|xlsx|pptx)$/.test(name) || /officedocument/i.test(mime);
return office ? [{ json: $json, binary: $binary }] : [];

const content = String($json.content || '').trim();
const readable = Boolean($json.ok) && content.length > 0 && !$json.needs_ai_fallback;
return readable ? [{ json: $json }] : [];

const content = String($json.content || '').trim();
const needsFallback = !$json.ok || !content || Boolean($json.needs_ai_fallback);
if (!needsFallback) return [];
const downloaded = $('Download Document').first();
return [{ json: $json, binary: downloaded.binary }];

const original = $('Normalize Telegram Input').first().json;
const extracted = String($json.content || '').trim();
const caption = String(original.normalized_text || '').trim();
const normalized = [caption, extracted].filter(Boolean).join('\n\n').slice(0, 120000).trim();
const metadata = $json.metadata && typeof $json.metadata === 'object' ? $json.metadata : {};
return [{ json: {
  ...original,
  raw_text: caption || extracted.slice(0, 1000),
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: {
    ...original.raw_payload,
    extraction: {
      provider: 'document-reader',
      status: 'office_text_extracted',
      format: metadata.format || null,
      extracted_characters: Number($json.characters || extracted.length),
      stored_characters: Number($json.stored_characters || normalized.length),
      truncated: Boolean($json.truncated),
      metadata
    }
  }
} }];

const text = String($json.text || '').trim();
const compactLength = text.replace(/\s+/g, '').length;
const pages = Number($json.numpages || 0);
const minimum = Math.max(80, Math.min(pages || 1, 20) * 25);
return compactLength >= minimum ? [{ json: $json, binary: $binary }] : [];

const text = String($json.text || '').trim();
const compactLength = text.replace(/\s+/g, '').length;
const pages = Number($json.numpages || 0);
const minimum = Math.max(80, Math.min(pages || 1, 20) * 25);
return compactLength < minimum ? [{ json: $json, binary: $binary }] : [];

const original = $('Normalize Telegram Input').first().json;
const fullText = String($json.text || '').replace(/\r/g, '').replace(/[ \t]+/g, ' ').replace(/ *\n */g, '\n').replace(/\n{3,}/g, '\n\n').trim();
const pages = Number($json.numpages || 0);
const info = $json.info && typeof $json.info === 'object' ? $json.info : {};
const title = String(info.Title || info.title || original.file_name || '').trim();
const author = String(info.Author || info.author || '').trim();
const truncated = fullText.length > 120000 || pages > 300;
const extracted = fullText.slice(0, 120000);
const caption = String(original.normalized_text || '').trim();
const header = [
  title ? `Назва документа: ${title}` : '',
  author ? `Автор: ${author}` : '',
  pages ? `Сторінок у PDF: ${pages}` : '',
  truncated ? 'Примітка: для аналізу збережено перші 300 сторінок або 120000 символів.' : ''
].filter(Boolean).join('\n');
const normalized = [caption, header, extracted].filter(Boolean).join('\n\n').trim();
return [{ json: {
  ...original,
  raw_text: caption || title || extracted.slice(0, 1000),
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: {
    ...original.raw_payload,
    extraction: {
      provider: 'pdfjs',
      status: 'text_layer',
      pages,
      pages_read: Math.min(pages, 300),
      title: title || null,
      author: author || null,
      extracted_characters: fullText.length,
      stored_characters: extracted.length,
      truncated
    }
  }
} }];

const original = $('Normalize Telegram Input').first().json;
const buffer = Buffer.from(String($json.document_base64 || ''), 'base64');
const extracted = buffer.toString('utf8').replace(/^\uFEFF/, '').trim();
const caption = String(original.normalized_text || '').trim();
const normalized = [caption, extracted].filter(Boolean).join('\n\n').slice(0, 120000).trim();
return [{ json: {
  ...original,
  raw_text: caption || extracted.slice(0, 1000),
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: { ...original.raw_payload, extraction: { provider: 'local-text', status: 'text_file', media_kind: original.media_kind, extracted_characters: extracted.length, stored_characters: normalized.length, truncated: extracted.length > 120000 } }
} }];

const original = $('Normalize Telegram Input').first().json;
const parts = $json.content?.parts || $json.candidate?.content?.parts || [];
const extracted = parts.map((part) => part.text || '').filter(Boolean).join('\n').trim()
  || String($json.text || $json.output || '').trim();
const caption = String(original.normalized_text || '').trim();
const normalized = [caption, extracted].filter(Boolean).join('\n\n').slice(0, 120000).trim();
const isPdf = String(original.mime_type || '').toLowerCase() === 'application/pdf' || /\.pdf$/i.test(String(original.file_name || ''));
return [{ json: {
  ...original,
  raw_text: caption || extracted.slice(0, 1000),
  normalized_text: normalized,
  supported: normalized.length > 0,
  raw_payload: {
    ...original.raw_payload,
    extraction: {
      provider: isPdf ? 'gemini-pdf-ocr' : 'gemini',
      status: isPdf ? 'ocr_fallback' : 'ai_document',
      media_kind: original.media_kind,
      extracted_characters: extracted.length,
      stored_characters: normalized.length,
      truncated: extracted.length > 120000
    }
  }
} }];

const row = $json;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
let reply;

if (!row.authorized) {
  reply = '⛔ Доступ до Inbox Agent не дозволено.';
} else if (!row.supported) {
  reply = 'Не вдалося витягти зміст. Підтримуються текст, посилання, голос, фото, PDF та поширені документи; архіви додамо окремо.';
} else if (row.created) {
  const labels = { link: 'посилання', text: 'текст', voice: 'голос', photo: 'зображення', file: 'файл' };
  const kind = labels[row.content_type] || 'матеріал';
  reply = `📥 Збережено ${kind} у Inbox.\n\n${row.preview}`;
} else {
  reply = `♻️ Цей матеріал уже є в Inbox.\n\n${row.preview}`;
}

return [{ json: { chat_id: row.source_chat_id, reply: escapeHtml(reply), item_id: row.item_id || null } }];

const row = $json;
if (!row.authorized || !row.supported || !row.created || !row.item_id) {
  return [];
}
return [{ json: { item_id: row.item_id } }];

const row = $json;
if (!row.created || !['voice', 'photo', 'file'].includes(row.content_type)) return [];
return [{ json: {
  inbox_item_id: row.item_id,
  kind: row.media_kind === 'document' ? 'document' : row.media_kind,
  original_name: row.file_name,
  mime_type: row.mime_type,
  size_bytes: row.file_size,
  telegram_file_id: row.file_id,
  file_unique_id: row.file_unique_id
} }];

parameters.query:
INSERT INTO inbox.attachments (inbox_item_id, kind, original_name, mime_type, size_bytes, telegram_file_id, metadata)
VALUES ($1::uuid, $2::text, nullif($3::text, ''), nullif($4::text, ''), nullif($5::bigint, 0), nullif($6::text, ''), jsonb_build_object('telegram_file_unique_id', $7::text, 'storage', 'telegram'))
RETURNING id::text AS attachment_id, inbox_item_id::text AS inbox_item_id, kind;
